def PublishArticle(title: str, content: str, reviewer: str) -> dict:
    if not ValidateContent(title, content):
        return {"article_id": None, "published_at": None, "reviewer": None, "status": "validation_failed", "word_count": None}
    article_id = SchedulePublish(title, content)
    notified = NotifyReviewer(reviewer, article_id)
    return {"article_id": article_id, "published_at": None, "reviewer": reviewer, "status": "published" if notified else "notification_failed", "word_count": len(content.split())}

